public struct FfiHabit {
    public var name: String
    public var period: String
    public var timesPerPeriod: Int32
    public var goalType: String
    public var totalTarget: Int32?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(name: String, period: String, timesPerPeriod: Int32, goalType: String, totalTarget: Int32?) {
        self.name = name
        self.period = period
        self.timesPerPeriod = timesPerPeriod
        self.goalType = goalType
        self.totalTarget = totalTarget
    }
}



extension FfiHabit: Equatable, Hashable {
    public static func ==(lhs: FfiHabit, rhs: FfiHabit) -> Bool {
        if lhs.name != rhs.name {
            return false
        }
        if lhs.period != rhs.period {
            return false
        }
        if lhs.timesPerPeriod != rhs.timesPerPeriod {
            return false
        }
        if lhs.goalType != rhs.goalType {
            return false
        }
        if lhs.totalTarget != rhs.totalTarget {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(name)
        hasher.combine(period)
        hasher.combine(timesPerPeriod)
        hasher.combine(goalType)
        hasher.combine(totalTarget)
    }
}


