public struct FfiTask {
    public var name: String
    public var dueTime: String?
    public var note: String?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(name: String, dueTime: String?, note: String?) {
        self.name = name
        self.dueTime = dueTime
        self.note = note
    }
}



extension FfiTask: Equatable, Hashable {
    public static func ==(lhs: FfiTask, rhs: FfiTask) -> Bool {
        if lhs.name != rhs.name {
            return false
        }
        if lhs.dueTime != rhs.dueTime {
            return false
        }
        if lhs.note != rhs.note {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(name)
        hasher.combine(dueTime)
        hasher.combine(note)
    }
}


